1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	type Item = { type: string };
13	type Step = { op: string; items: Item[] };
14	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
15	
16	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
17	
18	const quoteStep = (step: Step): { premium: number } => {
19	  const base = step.items.reduce((sum, item) => sum + itemBasePremium(item), 0);
20	  const firstInsurance = base * FIRST_INSURANCE_RATE;
21	  return { premium: Math.ceil(base + firstInsurance + PROCESSING_FEE) };
22	};
23	
24	export const runScenario = (scenario: unknown): unknown => {
25	  const { steps } = scenario as Scenario;
26	  return { results: steps.map(quoteStep) };
27	};
